#include <stdio.h>
#include <stdlib.h>

int minOperations(int* R, int N, int K, int M) {
    int minOps = 100;
    for (int mask = 0; mask < (1 << N); mask++) {
        int ops = 0;
        int* temp = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            temp[i] = R[i];
            if ((mask & (1 << i)) != 0) {
                temp[i]++;
                ops++;
            }
        }
        int valid = 1;
        for (int i = 0; i <= N - K; i++) {
            int maxVal = temp[i];
            int maxCount = 0;
            for (int j = i; j < i + K; j++) {
                if (temp[j] > maxVal) {
                    maxVal = temp[j];
                    maxCount = 1;
                } else if (temp[j] == maxVal) {
                    maxCount++;
                }
            }
            if (maxCount >= M) {
                valid = 0;
                break;
            }
        }
        if (valid == 1) {
            if(minOps > ops) minOps = ops;
        }
        free(temp);
    }
    if (minOps == 100) return -1;
    return minOps;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N, K, M;
        scanf("%d %d %d", &N, &K, &M);
        int* R = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &R[i]);
        }
        printf("%d\n", minOperations(R, N, K, M));
        free(R);
    }
    return 0;
}

